function doubleDamageDice(damage) {
  return damage.replace(/(\d+)?d(\d+)/g, (match, n, d) => {
    n = n ? parseInt(n) * 2 : 2; // If n is undefined, it means 1d, so we use 2
    return `${n}d${d}`;
  });
}

