    message = `**[center][color=red]FAILURE[/color] [gm]vs DC ${dc}[/gm][/center]**`
  }
}

api.sendMessage(message, data.roll, [], [{
  name: rollName || "Save",
  tooltip: tooltip || `${rollName || ""} Saving Throw`
}]);

// Here we update the character that rolled with the result
// And update the hpByLevelMap at record?.data?.hpByLevel
const className = data?.roll?.metadata?.className;
const newLevel = data?.roll?.metadata?.newLevel;
const newHitDie = data?.roll?.metadata?.newHitDie;
const newHp = data?.roll?.total;

const recordId = record?._id;
const hpByLevel = JSON.parse(record?.data?.hpByLevel || '[]');

if (className && newLevel && newHitDie && newHp && recordId) {
	const conMod = parseInt(record?.data?.constitutionMod || '0', 10);
	// Add newHp + conMod
	let hpToAdd = newHp + conMod;
	if (hpToAdd < 0) { hpToAdd = 1; }
	const curHpMax = parseInt(record?.data?.hitpoints || '0', 10);
	const curHp  = parseInt(record?.data?.curhp || '0', 10); 

	// Set curhp and hitpoints
	api.setValue('data.hitpoints', curHpMax + hpToAdd);
	api.setValue('data.curhp', curHp + hpToAdd);

	// Set hpByLevel map
	hpByLevel.push({
		className: className,
		level: newLevel,
		hitDie: newHitDie,
		hp: newHp
	});
	api.setValue('data.hpByLevel', JSON.stringify(hpByLevel));

	// Add a hitdie
	const hitDieField = `${newHitDie}HitDie`;
	const numHitDie = parseInt(record.data[hitDieField] || '0', 10);
	api.setValue(`data.${hitDieField}`, numHitDie + 1);

	// Send a Message
	const newHpMax = curHpMax + hpToAdd;
	const characterName = record?.name || 'New Character';
	api.sendMessage(`Added 1 Level of ${className} to ${characterName}.\n\n[color=green]New Hit Point Total:[/color] ${newHpMax}`, data.roll, [], []);
}

// Here we need to determine if it was a hit or miss and display in the chat.
const tags = [{
  name: "Healing",
  tooltip: "Healing Roll"
}];

const mods = data.roll?.metadata?.modifiers || [];

mods.forEach(mod => {
  if (mod.value > 0) {
    tags.push({
      name: mod.name,
      tooltip: `Modifier for ${mod.name.charAt(0).toUpperCase() + mod.name.slice(1)}`
    });
  }
});

const message = `
\`\`\`Apply_Healing
const healing = ${data.roll.total};

let targets = api.getSelectedOrDroppedToken();

// If record is not null, check if we're the GM or owner and use it
if (record) {
  if (isGM || record?.record?.ownerId === userId) {
    targets = [record];
  }
}

// If we're a player and we did not drop on a record, get our owned tokens
if (!isGM && targets.length === 0) {
    targets = api.getSelectedOwnedTokens().map(target => target.token);
}

targets.forEach(target => {
  // Apply healing
  if (target && target.data) {
      var curhp = target.data?.curhp || 0;
      curhp += healing;
      if (curhp > target.data?.hitpoints) { curhp = target.data?.hitpoints; }
      const oldHp = (target.data?.curhp || 0);
      api.setValueOnToken(target, "data.curhp", curhp);
      const unIdentified = target.identified === false;
      const targetName = !unIdentified ? target.name || target.record.name : target.unidentifiedName || target.record.unidentifiedName;

      const macro = \`\\\`\\\`\\\`Undo\\n if (isGM) { api.setValueOnTokenById('\$\{target._id\}', '\$\{target.recordType\}', 'data.curhp', '\$\{oldHp\}'); api.editMessage(null, '~\$\{targetName\} healed for \$\{healing\} HP.~'); } else { api.showNotification('Only the GM can undo healing.', 'yellow', 'Notice'); } \\n\\\`\\\`\\\`\`;

      api.sendMessage(\`\$\{targetName\} healed for \$\{healing\} HP.\\n\$\{macro\}\`, undefined, undefined, undefined, target);
  }
});
\`\`\`
`;

// Here you would check targets and apply damage, etc.
api.sendMessage(message, data.roll, [], tags);

// Here we heal the charcter by the amount rolled 
// And deduct 1 hit die from their total remaining

const recordId = record?._id;
const hitDieField = data?.roll?.metadata?.hitDieField;

// Requery the record incase multiple dice are being used
api.getRecord('characters', recordId, (record) => {
  // Update hit die remaining
  const hitDieRemaining = parseInt(record?.data?.[hitDieField] || '0', 10);

  if (hitDieRemaining) {

    const valuesToSet = {};
    if (hitDieRemaining && hitDieField && recordId) {
      valuesToSet[`data.${hitDieField}`] = hitDieRemaining - 1 <= 0 ? null : hitDieRemaining - 1;
    }

    // Add the amount rolled + con mod to the character's curhp
    let amountToAdd = data?.roll?.total;
    // Minimum of 1
    if (amountToAdd <= 0) { amountToAdd = 1; }

    const maxHp = parseInt(record?.data?.hitpoints || '0', 10);
    let newHp = amountToAdd + parseInt(record?.data?.curhp || '0', 10);
    if (newHp > maxHp) {
      // Not to exceed max hp
      newHp = maxHp;
    }

    valuesToSet['data.curhp'] = newHp;

    api.setValues(valuesToSet);

    const tags = [{
      name: "Hit Die",
      tooltip: "Hit Die Roll"
    }];

    // Send a message
    api.sendMessage(`[center]Recovered ${amountToAdd} HP[/center]`, data.roll, [], tags);
  }
  else {
    api.showNotification(`No Hit Die Remaining for ${record?.name}`, 'red', "No Hit Dice");
  }
});

// Perform a death save, which is always DC 10, and mark up or down the character's death save success/failure count
const recordId = record?._id;

// Hardcoded for death saves
const dc = 10;

// Requery the record incase rolling multiple death saves
api.getRecord('characters', recordId, (record) => {
  // Compare roll to DC

  const criticalSuccess = data?.roll?.total - data?.roll?.modifier >= 20;
  const criticalFailure = data?.roll?.total - data?.roll?.modifier <= 1;
  const normalSuccess = data?.roll?.total - data?.roll?.modifier >= dc;

  const tags = [{
    name: "Death Save",
    tooltip: "Death Save Roll"
  }];

  const valuesToSet = {};
  let numFailures = parseInt(record?.data?.deathSaveFailures || '0', 10);
  let numSuccesses = parseInt(record?.data?.deathSaveSuccesses || '0', 10);

  if (criticalSuccess) {
    // Add 1 HP
    const maxHp = parseInt(record?.data?.hitpoints || '0', 10);
    let newHp = 1 + parseInt(record?.data?.curhp || '0', 10);
    if (newHp > maxHp) {
      // Not to exceed max hp
      newHp = maxHp;
    }
    valuesToSet['data.curhp'] = newHp;
    api.sendMessage(`**[center][color=green]CRITICAL SUCCESS[/color][/center]**\n\n[center]Regaining 1 HP.[/center]`, data.roll, [], []);
  }
  else if (criticalFailure) {
    // Add 2 failures
    numFailures += 2;
    if (numFailures >= 3) {
      numFailures = 3;
    }
    valuesToSet['data.deathSaveFailures'] = numFailures;
    api.sendMessage(`**[center][color=red]CRITICAL FAILURE[/color][/center]**`, data.roll, [], tags);
  }
  else if (normalSuccess) {
    // Add 1 success
    numSuccesses += 1;
    if (numSuccesses >= 3) {
      numSuccesses = 3;
    }
    valuesToSet['data.deathSaveSuccesses'] = numSuccesses;
    api.sendMessage(`**[center][color=green]SUCCESS[/color][/center]**`, data.roll, [], tags);
  }
  else {
    // Add 1 failure
    numFailures += 1;
    valuesToSet['data.deathSaveFailures'] = numFailures;
    api.sendMessage(`**[center][color=red]FAILURE[/color][/center]**`, data.roll, [], tags);
  }

  api.setValues(valuesToSet);

  // If 3 failures add "Dead" effect to character

  if (numFailures >= 3) {
    const tokenForRecord = api.getToken();
    if (tokenForRecord) {
      api.addEffect('Dead', tokenForRecord);
    }
  }
});

const rollName = data?.roll?.metadata?.rollName;
const tooltip = data?.roll?.metadata?.tooltip;

let message = '';

let dc = 0;
dc = parseInt(data?.roll?.metadata?.dc || '0', 10);
if (isNaN(dc)) {
  dc = 0;
}
if (dc > 0) {
  const total = data?.roll?.total || 0;
  if (total >= dc) {
    message = `**[center][color=green]SUCCESS[/color] [gm]vs DC ${dc}[/gm][/center]**`
  }
  else {
    // Here we need to remove the Concentration effect.
    const effects = record?.effects || [];
    const concentrationEffect = effects.find(effect => effect.name === 'Concentration');
    let oldSpellName = '';
    if (concentrationEffect) {
      const tokenForRecord = api.getToken();
      const oldValues = tokenForRecord?.effectValues || {};
      if (oldValues[concentrationEffect?._id]) {
        oldSpellName = oldValues[concentrationEffect?._id];
      }
      lostConcentrationOn = oldSpellName;
      api.removeEffectById(concentrationEffect._id, tokenForRecord);
    }
    message = `**[center][color=red]FAILURE[/color] [gm]vs DC ${dc}[/gm][/center]**`
    if (oldSpellName) {
      message += `\n\n[center]Lost concentration on ${oldSpellName}.[/center]`;
    }
  }
}

api.sendMessage(message, data.roll, [], [{
  name: rollName || "Save",
  tooltip: tooltip || `${rollName || ""} Saving Throw`
}]);
